#!/usr/bin/env python3
"""
================================================================================
 SAAT - Solar-Powered Automated Agricultural Technology
 Pear Sorting & Packaging System - FULL SOFTWARE SIMULATION
================================================================================

WHAT THIS IS
------------
This is a pure-software simulation of the SAAT ROS2 pipeline described in the
project README and Vision System documentation. It reproduces:

  - The 6-zone (A1,A2,A3,B1,B2,B3) vision inspection grid
  - The 9-step vision pipeline OUTCOME (infection_ratio, is_infected, area,
    centroid, dominant colour) - simulated statistically instead of running
    real OpenCV/TFLite on a real camera feed
  - The accept/reject decision rule (infection_ratio >= 0.03 -> REJECTED)
  - Pear size categorisation (BIG/SMALL at 15,000 px^2)
  - Volume/mass estimation (density = 0.96 g/cm3)
  - The 7-step centroid speed-tracking + PID belt-voltage algorithm, including
    the hard constraint Conv1_V + Conv2_V = 3.3 V, and the EMPTY / NORMAL /
    CROWDED belt states
  - The 13-field SQLite database schema (`pear_records`), written in the
    real system's A1->A2->A3->B1->B2->B3 order
  - packaging_node: a package = 12 BIG pears (upper layer) + 12 SMALL pears
    (lower layer) = 24 pears. Completed packages are stored in a `packages`
    table and rendered as printable labels on a new /labels page:
      - Label Type 1: one Master Package Label per package (upper/lower
        layer grids, per-layer + total mass, package ID, packaging time,
        packaging clock, SAAT logo)
      - Label Type 2: one small individual label per pear in the package
        (rounded SAAT logo + Package ID + Pear ID)
  - The Flask SCADA dashboard at :8080 with 4 routes: "/", "/database",
    "/labels" (+ "/labels/<package_id>"), "/api/status" - styled to match
    the real dashboard's dark IIoT look (colours/fonts taken from the
    README's design token table, and layout matched to the screenshots
    supplied)

NOTHING here touches real hardware. There is no RealSense camera, no
PCA9685/servo I2C bus, no Jetson.GPIO, no PLC. Every number you see is
generated by this script's internal statistical model, running entirely in
software, to let you preview exactly what the dashboard/database/API will
look like and what kind of values to expect once the real system is running.

HOW TO RUN
----------
    pip install flask
    python3 saat_simulation.py

Then open:
    http://localhost:8080 <- Status page (matches screenshots)
    http://localhost:8080/database <- SQLite viewer (200 most recent pears)
    http://localhost:8080/labels <- Label Generator (completed packages)
    http://localhost:8080/api/status <- JSON API (raw 13-field payload)

Stop with CTRL+C. The script creates saat_simulation.db (SQLite) next to
itself; delete it to reset all simulated history.
================================================================================
"""

import json
import math
import os
import random
import sqlite3
import threading
import time
from datetime import datetime, timezone

from flask import Flask, jsonify, render_template_string

# ==============================================================================
# EMBEDDED LOGO ASSETS (base64, so this stays a single self-contained file)
# Source: user-supplied SAAT logo (gear + leaf + circuit mark). Two crops are
# embedded: a square icon-only crop (for small rounded pear labels) and the
# full trimmed logo (for the master package label / dashboard branding).
# ==============================================================================

LOGO_ICON_B64 = ""
LOGO_FULL_B64 = ""

LOGO_ICON_DATA_URI = "data:image/png;base64," + LOGO_ICON_B64
LOGO_FULL_DATA_URI = "data:image/png;base64," + LOGO_FULL_B64

# ==============================================================================
# CONFIGURATION (mirrors src/saat_core/config/saat_params.yaml)
# ==============================================================================

ZONES = ["A1", "A2", "A3", "B1", "B2", "B3"]

CONV1_LENGTH_CM = 175 # Conv 1 - Loading belt
CONV2_LENGTH_CM = 115 # Conv 2 - Packing belt

INFECTION_RATIO_THRESHOLD = 0.03 # 3% -> REJECTED
BIG_PEAR_AREA_PX = 15000.0 # px^2 threshold BIG/SMALL
PEAR_DENSITY_G_CM3 = 0.96 # mass_estimation_node

MIN_VOLTAGE = 0.1 # V, never true-zero to PLC
MAX_VOLTAGE = 3.3 # V, hard system constraint
VOLTAGE_SUM = 3.3 # Conv1_V + Conv2_V == 3.3 V ALWAYS

REF_SPEED_MAX_MS = 0.5 # speed_publisher_node scaling reference
RETURN_DELAY_S = 0.4 # servo return delay (x2 for full cycle)

# packaging_node: one package = 12 BIG (upper layer) + 12 SMALL (lower layer)
BIG_PER_PACKAGE = 12
SMALL_PER_PACKAGE = 12
PEARS_PER_PACKAGE = BIG_PER_PACKAGE + SMALL_PER_PACKAGE

DB_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), "saat_simulation.db")

TICK_SECONDS = 1.0 # simulation heartbeat (per-zone check)
IOT_STATUS_PERIOD_S = 10.0 # /iot_status publish rate -> 0.1 Hz
DASHBOARD_REFRESH_S = 10 # matches "Refresh: 10 s" in the SCADA UI

app = Flask(__name__)
_lock = threading.Lock()


# ==============================================================================
# SIMULATION STATE
# ==============================================================================

def utc_now_iso():
    return datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%M:%S")


def format_clock(seconds):
    """Elapsed packaging time as MM:SS (packaging_clock on the master label)."""
    seconds = max(0, int(seconds))
    m, s = divmod(seconds, 60)
    return f"{m:02d}:{s:02d}"


class ZoneState:
    """Mirrors what MotorStatus.msg + InfectionResult.msg track per zone."""

    def __init__(self, zone_id):
        self.zone_id = zone_id
        self.last_action = "IDLE" # ACCEPTED | REJECTED | IDLE
        self.infection_ratio = 0.0
        self.infection_area_px = 0.0
        self.pear_area_px = 0.0
        self.servo_active = False
        self.busy_until = 0.0 # epoch seconds; zone shows result until this


class SystemState:
    """Global system state - equivalent to what data_collection_node /
    webpage_publisher_node hold in memory, aggregated from all topics."""

    def __init__(self):
        self.zones = {z: ZoneState(z) for z in ZONES}
        self.pear_counter = {z: 0 for z in ZONES}

        # /iot_status running totals
        self.batch_accepted = 0
        self.batch_rejected = 0
        self.total_accepted = 0
        self.total_rejected = 0
        self.small_count = 0
        self.big_count = 0
        self.completed_packages = 0
        self._mass_running_sum = 0.0
        self._mass_running_n = 0

        # packaging_node: current in-progress package + counters
        self.package_counter = 0
        self.current_package_big = []      # ordered list of pear_id (accepted BIG)
        self.current_package_small = []    # ordered list of pear_id (accepted SMALL)
        self.current_package_start_time = time.time()
        self.last_package_id = None

        # last pear
        self.last_pear_id = None
        self.last_pear_zone = None

        # /main_speed, /speed_to_plc (SpeedCommand.msg)
        self.reference_speed_ms = 0.0
        self.conv1_voltage = MIN_VOLTAGE
        self.conv2_voltage = VOLTAGE_SUM - MIN_VOLTAGE
        self.belt_state = "EMPTY" # EMPTY | NORMAL | CROWDED
        self.vision_pear_count = 0
        self.avg_mass_g = 0.0

        self.system_running = True
        self.started_at = utc_now_iso()
        self.last_updated = utc_now_iso()
        self.last_iot_publish = 0.0

    # ---- helpers -------------------------------------------------------

    def record_mass(self, mass_g):
        self._mass_running_sum += mass_g
        self._mass_running_n += 1
        self.avg_mass_g = self._mass_running_sum / self._mass_running_n

    def to_iot_status(self):
        """The aggregated /iot_status JSON payload (matches the 13-field
        schema fanned out per-zone, plus the system-wide summary the
        dashboard needs)."""
        return {
            "zones": {
                z: {
                    "last_action": s.last_action,
                    "infection_ratio": round(s.infection_ratio, 4),
                    "infection_area_px": round(s.infection_area_px, 1),
                    "pear_area_px": round(s.pear_area_px, 1),
                    "servo_active": s.servo_active,
                }
                for z, s in self.zones.items()
            },
            "conv1_voltage": round(self.conv1_voltage, 2),
            "conv2_voltage": round(self.conv2_voltage, 2),
            "belt_state": self.belt_state,
            "vision_pear_count": self.vision_pear_count,
            "reference_speed_ms": round(self.reference_speed_ms, 3),
            "batch_accepted": self.batch_accepted,
            "batch_rejected": self.batch_rejected,
            "total_accepted": self.total_accepted,
            "total_rejected": self.total_rejected,
            "small_count": self.small_count,
            "big_count": self.big_count,
            "completed_packages": self.completed_packages,
            "avg_mass_g": round(self.avg_mass_g, 2),
            "last_pear_id": self.last_pear_id,
            "last_pear_zone": self.last_pear_zone,
            "last_package_id": self.last_package_id,
            "current_package_big_count": len(self.current_package_big),
            "current_package_small_count": len(self.current_package_small),
            "system_running": self.system_running,
            "updated": self.last_updated,
        }


state = SystemState()


# ==============================================================================
# DATABASE (13-field schema, exactly as in the README)
# ==============================================================================

def db_init():
    conn = sqlite3.connect(DB_PATH)
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS pear_records (
            pear_id TEXT PRIMARY KEY,
            zone_id TEXT,
            timestamp REAL,
            pear_status TEXT,
            pear_category TEXT,
            infection_area_px REAL,
            infection_location TEXT,
            infection_color_rgb TEXT,
            infection_ratio REAL,
            pear_surface_area_px REAL,
            pear_volume_cm3 REAL,
            pear_mass_g REAL,
            belt_speed_ms REAL
        )
        """
    )
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS packages (
            package_id           TEXT PRIMARY KEY,
            completed_at         REAL,
            packaging_time_str   TEXT,
            packaging_clock_s    REAL,
            upper_mass_g         REAL,
            lower_mass_g         REAL,
            total_mass_g         REAL,
            upper_pear_ids       TEXT,
            lower_pear_ids       TEXT
        )
        """
    )
    conn.commit()
    conn.close()


def db_insert(record):
    conn = sqlite3.connect(DB_PATH)
    conn.execute(
        """
        INSERT INTO pear_records
            (pear_id, zone_id, timestamp, pear_status, pear_category,
             infection_area_px, infection_location, infection_color_rgb,
             infection_ratio, pear_surface_area_px, pear_volume_cm3,
             pear_mass_g, belt_speed_ms)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)
        """,
        (
            record["pear_id"], record["zone_id"], record["timestamp"],
            record["pear_status"], record["pear_category"],
            record["infection_area_px"], record["infection_location"],
            record["infection_color_rgb"], record["infection_ratio"],
            record["pear_surface_area_px"], record["pear_volume_cm3"],
            record["pear_mass_g"], record["belt_speed_ms"],
        ),
    )
    conn.commit()
    conn.close()


def db_fetch_recent(limit=200):
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    rows = conn.execute(
        "SELECT * FROM pear_records ORDER BY timestamp DESC LIMIT ?", (limit,)
    ).fetchall()
    conn.close()
    return [dict(r) for r in rows]


def db_fetch_pears_by_ids(pear_ids):
    """Fetch full pear_records rows for a list of pear_id, keyed by pear_id."""
    if not pear_ids:
        return {}
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    placeholders = ",".join("?" for _ in pear_ids)
    rows = conn.execute(
        f"SELECT * FROM pear_records WHERE pear_id IN ({placeholders})", pear_ids
    ).fetchall()
    conn.close()
    return {r["pear_id"]: dict(r) for r in rows}


def db_insert_package(record):
    conn = sqlite3.connect(DB_PATH)
    conn.execute(
        """
        INSERT INTO packages
            (package_id, completed_at, packaging_time_str, packaging_clock_s,
             upper_mass_g, lower_mass_g, total_mass_g, upper_pear_ids, lower_pear_ids)
        VALUES (?,?,?,?,?,?,?,?,?)
        """,
        (
            record["package_id"], record["completed_at"], record["packaging_time_str"],
            record["packaging_clock_s"], record["upper_mass_g"], record["lower_mass_g"],
            record["total_mass_g"], record["upper_pear_ids"], record["lower_pear_ids"],
        ),
    )
    conn.commit()
    conn.close()


def db_fetch_packages(limit=50):
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    rows = conn.execute(
        "SELECT * FROM packages ORDER BY completed_at DESC LIMIT ?", (limit,)
    ).fetchall()
    conn.close()
    return [dict(r) for r in rows]


def db_fetch_package(package_id):
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    row = conn.execute(
        "SELECT * FROM packages WHERE package_id = ?", (package_id,)
    ).fetchone()
    conn.close()
    return dict(row) if row else None


def db_load_counters():
    """Resume pear_id / package_id numbering from whatever is already in
    saat_simulation.db instead of restarting at 1 each run. Without this,
    re-running the script against an existing DB immediately crashes with
    'UNIQUE constraint failed: pear_records.pear_id' the moment the fresh
    in-memory counters (which always start at 0) regenerate an ID that was
    already written to disk by a previous run."""
    conn = sqlite3.connect(DB_PATH)
    pear_counters = {z: 0 for z in ZONES}
    try:
        for pear_id, zone_id in conn.execute("SELECT pear_id, zone_id FROM pear_records"):
            try:
                n = int(pear_id.rsplit("_", 1)[-1])
            except (ValueError, AttributeError):
                continue
            if zone_id in pear_counters and n > pear_counters[zone_id]:
                pear_counters[zone_id] = n
    except sqlite3.OperationalError:
        pass  # table didn't exist yet (first ever run)

    package_counter = 0
    try:
        for (package_id,) in conn.execute("SELECT package_id FROM packages"):
            try:
                n = int(package_id.rsplit("-", 1)[-1])
            except (ValueError, AttributeError):
                continue
            if n > package_counter:
                package_counter = n
    except sqlite3.OperationalError:
        pass

    conn.close()
    return pear_counters, package_counter


def db_load_pending_package_pears():
    """Rebuild the in-progress package on startup: every ACCEPTED pear
    already in the DB that isn't inside any completed package's
    upper/lower pear-id list yet, oldest first, split by category. Keeps
    a restart from silently losing pears that were accepted but not yet
    packaged."""
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row

    packaged_ids = set()
    try:
        for row in conn.execute("SELECT upper_pear_ids, lower_pear_ids FROM packages"):
            packaged_ids.update(json.loads(row["upper_pear_ids"]))
            packaged_ids.update(json.loads(row["lower_pear_ids"]))
    except sqlite3.OperationalError:
        pass

    big, small = [], []
    try:
        rows = conn.execute(
            "SELECT pear_id, pear_category FROM pear_records "
            "WHERE pear_status='ACCEPTED' ORDER BY timestamp ASC"
        ).fetchall()
        for r in rows:
            if r["pear_id"] in packaged_ids:
                continue
            (big if r["pear_category"] == "BIG" else small).append(r["pear_id"])
    except sqlite3.OperationalError:
        pass

    conn.close()
    return big, small


# ==============================================================================
# VISION PIPELINE SIMULATION (statistical stand-in for the real 9-step
# OpenCV pipeline - same inputs/outputs/thresholds, randomised realistically)
# ==============================================================================

def simulate_vision_result():
    """Simulate one pear's outcome through the 9-step pipeline.
    ~78% of pears are healthy (low infection ratio), ~22% infected,
    matching typical packhouse reject rates used to tune the threshold
    (README calibration guide: 2%-5% typical threshold range)."""
    pear_area_px = random.uniform(9000, 22000)

    if random.random() < 0.22:
        infection_ratio = random.uniform(0.03, 0.22) # REJECTED range
    else:
        infection_ratio = max(0.0, random.gauss(0.008, 0.007)) # ACCEPTED range

    infection_ratio = min(infection_ratio, 0.35)
    infection_area_px = infection_ratio * pear_area_px
    is_infected = infection_ratio >= INFECTION_RATIO_THRESHOLD

    # infection centroid, inside the ~427x360 zone sub-frame
    infection_x = random.uniform(40, 387) if infection_area_px > 0 else 0.0
    infection_y = random.uniform(40, 320) if infection_area_px > 0 else 0.0

    # dominant colour of the infected patch: dark brown/black rot tones
    if is_infected:
        r = random.randint(30, 90)
        g = random.randint(15, 60)
        b = random.randint(5, 40)
    else:
        r = random.randint(150, 210)
        g = random.randint(170, 220)
        b = random.randint(60, 120)

    return {
        "pear_area_px": pear_area_px,
        "infection_ratio": infection_ratio,
        "infection_area_px": infection_area_px,
        "infection_x": infection_x,
        "infection_y": infection_y,
        "infection_rgb": (r, g, b),
        "is_infected": is_infected,
    }


def simulate_volume_mass(pear_area_px):
    """volume_estimation_node (depth->cm3) + mass_estimation_node
    (volume * density) simulated with realistic pear-size variance."""
    # correlate volume loosely with 2D silhouette area, add depth-sensor noise
    base_volume = 120 + (pear_area_px / BIG_PEAR_AREA_PX) * 90
    volume_cm3 = max(60.0, random.gauss(base_volume, 12.0))
    mass_g = volume_cm3 * PEAR_DENSITY_G_CM3
    return volume_cm3, mass_g


# ==============================================================================
# SPEED CONTROL SIMULATION (7-step centroid tracker + PID voltage mapping)
# ==============================================================================

def simulate_speed_step():
    """Simulate main_speed_node + speed_publisher_node for one tick."""
    # Step 1-2: pear count in the vision strip (mostly 0-6, rare overflow)
    count = max(0, round(random.gauss(2.2, 1.6)))
    if random.random() < 0.03:
        count += random.randint(5, 8) # rare CROWDED spike

    if count == 0:
        belt_state = "EMPTY"
        conv1_v, conv2_v = MAX_VOLTAGE, MIN_VOLTAGE
        ref_speed = 0.0
    elif count > 6:
        belt_state = "CROWDED"
        conv1_v, conv2_v = MIN_VOLTAGE, MAX_VOLTAGE
        ref_speed = REF_SPEED_MAX_MS
    else:
        belt_state = "NORMAL"
        # Steps 3-6: average pear displacement speed (m/s), with jitter
        ref_speed = max(0.02, random.gauss(0.28, 0.08))
        ref_speed = min(ref_speed, REF_SPEED_MAX_MS)
        # Step 7: map to voltage, enforce Conv1+Conv2 = 3.3V constraint
        conv2_v = (ref_speed / REF_SPEED_MAX_MS) * VOLTAGE_SUM
        conv2_v = min(max(conv2_v, MIN_VOLTAGE), MAX_VOLTAGE)
        conv1_v = VOLTAGE_SUM - conv2_v
        conv1_v = min(max(conv1_v, MIN_VOLTAGE), MAX_VOLTAGE)
        conv2_v = VOLTAGE_SUM - conv1_v # re-enforce exact sum after clamping

    return belt_state, count, ref_speed, round(conv1_v, 2), round(conv2_v, 2)


# ==============================================================================
# MAIN SIMULATION LOOP (background thread - plays the role of every ROS2
# node running together: vision_node x6, action_node x6, data_collector x6,
# area/volume/mass nodes, main_speed_node, speed_publisher_node,
# data_collection_node)
# ==============================================================================

def finalize_package(now):
    """packaging_node: called (with _lock already held) the instant a
    package reaches 12 BIG + 12 SMALL accepted pears. Slices off exactly
    12+12 pear_ids (oldest first), looks up their real DB records for
    mass, writes the `packages` row, and rolls any surplus pears (a race
    where both layers crossed 12 in the same tick) into the next package."""
    upper_ids = state.current_package_big[:BIG_PER_PACKAGE]
    lower_ids = state.current_package_small[:SMALL_PER_PACKAGE]
    state.current_package_big = state.current_package_big[BIG_PER_PACKAGE:]
    state.current_package_small = state.current_package_small[SMALL_PER_PACKAGE:]

    pear_rows = db_fetch_pears_by_ids(upper_ids + lower_ids)
    upper_mass_g = sum(pear_rows[pid]["pear_mass_g"] for pid in upper_ids if pid in pear_rows)
    lower_mass_g = sum(pear_rows[pid]["pear_mass_g"] for pid in lower_ids if pid in pear_rows)

    state.package_counter += 1
    package_id = f"PKG-{state.package_counter:05d}"
    clock_s = now - state.current_package_start_time

    record = {
        "package_id": package_id,
        "completed_at": now,
        "packaging_time_str": utc_now_iso(),
        "packaging_clock_s": round(clock_s, 1),
        "upper_mass_g": round(upper_mass_g, 2),
        "lower_mass_g": round(lower_mass_g, 2),
        "total_mass_g": round(upper_mass_g + lower_mass_g, 2),
        "upper_pear_ids": json.dumps(upper_ids),
        "lower_pear_ids": json.dumps(lower_ids),
    }
    db_insert_package(record)

    state.completed_packages += 1
    state.last_package_id = package_id
    state.current_package_start_time = now


def simulation_loop():
    while True:
        now = time.time()
        with _lock:
            # ---- Layer 6: belt speed / voltage (runs every tick, ~ once/s
            # here; real system runs the PID at 10 Hz but the *values* are
            # representative of any given instant) -----------------------
            belt_state, count, ref_speed, conv1_v, conv2_v = simulate_speed_step()
            state.belt_state = belt_state
            state.vision_pear_count = count
            state.reference_speed_ms = ref_speed
            state.conv1_voltage = conv1_v
            state.conv2_voltage = conv2_v

            # ---- Layers 3-5: vision + action + data collection, write
            # order enforced A1 -> A2 -> A3 -> B1 -> B2 -> B3 -------------
            for zone_id in ZONES:
                zstate = state.zones[zone_id]

                # expire a finished action back to IDLE
                if zstate.last_action != "IDLE" and now >= zstate.busy_until:
                    zstate.last_action = "IDLE"
                    zstate.servo_active = False
                    zstate.infection_ratio = 0.0
                    zstate.infection_area_px = 0.0
                    zstate.pear_area_px = 0.0

                # a new pear can only enter an IDLE zone (mirrors physical
                # single-pear-per-slot constraint), ~35% chance per tick
                if zstate.last_action == "IDLE" and random.random() < 0.35:
                    vis = simulate_vision_result()
                    volume_cm3, mass_g = simulate_volume_mass(vis["pear_area_px"])

                    status = "REJECTED" if vis["is_infected"] else "ACCEPTED"
                    category = "BIG" if vis["pear_area_px"] > BIG_PEAR_AREA_PX else "SMALL"

                    state.pear_counter[zone_id] += 1
                    pear_id = f"{zone_id}_{state.pear_counter[zone_id]:05d}"

                    zstate.last_action = status
                    zstate.servo_active = True
                    zstate.infection_ratio = vis["infection_ratio"]
                    zstate.infection_area_px = vis["infection_area_px"]
                    zstate.pear_area_px = vis["pear_area_px"]
                    # full action cycle: reject/accept move + return (README: ~0.4s + 0.4s)
                    zstate.busy_until = now + (RETURN_DELAY_S * 2)

                    if status == "ACCEPTED":
                        state.batch_accepted += 1
                        state.total_accepted += 1
                    else:
                        state.batch_rejected += 1
                        state.total_rejected += 1

                    if category == "BIG":
                        state.big_count += 1
                    else:
                        state.small_count += 1

                    state.record_mass(mass_g)
                    state.last_pear_id = pear_id
                    state.last_pear_zone = zone_id

                    r, g, b = vis["infection_rgb"]
                    record = {
                        "pear_id": pear_id,
                        "zone_id": zone_id,
                        "timestamp": now,
                        "pear_status": status,
                        "pear_category": category,
                        "infection_area_px": round(vis["infection_area_px"], 1),
                        "infection_location": json.dumps(
                            {"x": round(vis["infection_x"], 1), "y": round(vis["infection_y"], 1)}
                        ),
                        "infection_color_rgb": json.dumps([r, g, b]),
                        "infection_ratio": round(vis["infection_ratio"], 4),
                        "pear_surface_area_px": round(vis["pear_area_px"], 1),
                        "pear_volume_cm3": round(volume_cm3, 2),
                        "pear_mass_g": round(mass_g, 2),
                        "belt_speed_ms": round(ref_speed, 3),
                    }
                    db_insert(record)

                    # ---- packaging_node: only ACCEPTED pears go into a
                    # package. Upper layer = 12 BIG, lower layer = 12 SMALL.
                    if status == "ACCEPTED":
                        if category == "BIG":
                            state.current_package_big.append(pear_id)
                        else:
                            state.current_package_small.append(pear_id)

                        if (len(state.current_package_big) >= BIG_PER_PACKAGE
                                and len(state.current_package_small) >= SMALL_PER_PACKAGE):
                            finalize_package(now)

            # ---- /iot_status publish gate (0.1 Hz, matches README) -------
            if now - state.last_iot_publish >= IOT_STATUS_PERIOD_S:
                state.last_iot_publish = now

            state.last_updated = utc_now_iso()

        time.sleep(TICK_SECONDS)


# ==============================================================================
# FLASK - SCADA DASHBOARD (dark IIoT theme, matches README design tokens
# and the two supplied screenshots exactly: header/badge, 5 stat cards,
# last-pear-id card, conveyor voltage bars, 6-zone status grid, footer)
