@app.route("/")
def index():
    return render_template_string(INDEX_HTML, css=BASE_CSS)


@app.route("/database")
def database():
    rows = db_fetch_recent(200)
    return render_template_string(DATABASE_HTML, css=BASE_CSS, rows=rows)


@app.route("/labels")
def labels_list():
    packages = db_fetch_packages(50)
    for p in packages:
        p["clock_str"] = format_clock(p["packaging_clock_s"])
    with _lock:
        current_big = len(state.current_package_big)
        current_small = len(state.current_package_small)
    return render_template_string(
        LABELS_LIST_HTML, css=BASE_CSS, packages=packages,
        current_big=current_big, current_small=current_small,
    )


@app.route("/labels/<package_id>")
def labels_sheet(package_id):
    pkg = db_fetch_package(package_id)
    if pkg is None:
        return f"Package '{package_id}' not found. <a href='/labels'>Back to Label Generator</a>", 404

    pkg["clock_str"] = format_clock(pkg["packaging_clock_s"])
    upper_ids = json.loads(pkg["upper_pear_ids"])
    lower_ids = json.loads(pkg["lower_pear_ids"])
    pear_rows = db_fetch_pears_by_ids(upper_ids + lower_ids)

    # preserve original P1..P12 slot order recorded at packaging time
    upper = [pear_rows[pid] for pid in upper_ids if pid in pear_rows]
    lower = [pear_rows[pid] for pid in lower_ids if pid in pear_rows]

    return render_template_string(
        LABEL_SHEET_HTML, css=BASE_CSS, pkg=pkg, upper=upper, lower=lower,
        logo_full=LOGO_FULL_DATA_URI, logo_icon=LOGO_ICON_DATA_URI,
    )


@app.route("/api/status")
def api_status():
    with _lock:
        return jsonify(state.to_iot_status())


# ==============================================================================
# ENTRYPOINT
# ==============================================================================

if __name__ == "__main__":
    db_init()

    # Resume from whatever's already in saat_simulation.db (if this isn't
    # the first run) so pear_id / package_id numbering picks up where it
    # left off instead of crashing on a UNIQUE constraint collision.
    pear_counters, package_counter = db_load_counters()
    pending_big, pending_small = db_load_pending_package_pears()
    state.pear_counter = pear_counters
    state.package_counter = package_counter
    state.current_package_big = pending_big
    state.current_package_small = pending_small
    if any(pear_counters.values()) or package_counter:
        print(f" Resuming from existing DB - pear counters: {pear_counters}, "
              f"next package will be PKG-{package_counter + 1:05d}")

    t = threading.Thread(target=simulation_loop, daemon=True)
    t.start()

    port = 8080
    print("=" * 70)
    print(" SAAT SIMULATION - SOFTWARE ONLY, NO HARDWARE INVOLVED")
    print("=" * 70)
    print(f" Status page : http://localhost:{port}")
    print(f" Database view: http://localhost:{port}/database")
    print(f" Label Generator: http://localhost:{port}/labels")
    print(f" JSON API : http://localhost:{port}/api/status")
    print(f" SQLite file : {DB_PATH}")
    print("=" * 70)
    app.run(host="0.0.0.0", port=port, threaded=True)